    dp[0][0] = mat[0][0]

    # Fill the first row
    for j in range(1, n):
        dp[0][j] = dp[0][j - 1] + mat[0][j]

    # Fill the first column
    for i in range(1, n):
        dp[i][0] = dp[i - 1][0] + mat[i][0]

